sql:
SELECT station_name, location
FROM weather_stations
WHERE elevation > (SELECT AVG(elevation) FROM weather_stations);

external_knowledge:
- "diverse and extensive collection" implies a high number of data points and types; 
- "detailed characteristics" refer to all columns from the weather station table;
- "counts of data points and types" correlate to the number of records and unique data types collected by the station.

sql:
SELECT DISTINCT station_name
FROM weather_stations
WHERE elevation > 500 AND station_name LIKE 'M%';

SELECT station_id
FROM weather_stations
WHERE installation_date = (SELECT MIN(installation_date) FROM weather_stations);
